...props}\n      >\n        {isLoading && <Spinner size=\"sm\" className=\"text-current\" />}\n        {!isLoading && icon && <span className=\"mr-2\">{icon}</span>}\n        <span className=\"mx-2\">{children}</span>\n      </Comp>\n    );\n  },\n);\nButton.displayName = 'Button';\n\nexport { Button, buttonVariants };\n",
